// Adapted from repo: original used 'ICP Score'/'ICP Reasoning' field names;
// our CRM actually has 'Lead Score'/'AI Reasoning'. Channel names also
// mapped to real workspace channel IDs (no #sales-leads/#founders-highlights/
// #marketing-attribution channels exist yet):
//   sales     -> #leads       (C0BFX7J46V7)
//   founders  -> #automations (C0BFX7KJAC9)
//   marketing -> #automations (C0BFX7KJAC9)
const CHANNELS = {
  salesLeads: 'C0BFX7J46V7',
  founders: 'C0BFX7KJAC9',
  marketing: 'C0BFX7KJAC9',
};

const HIGH_PRIORITY_THRESHOLD = 80;

export const code = async (inputs) => {
  const { crmRecord, territory, repPool } = inputs;
  const f = crmRecord.fields || {};
  const messages = [];

  const salesText =
    `*New lead routed to ${repPool}*\n` +
    `*Company:* ${f.Company ?? 'Unknown'}\n` +
    `*Contact:* ${f['Full Name'] ?? 'Unknown'} <${f.Email ?? ''}>\n` +
    `*Lead Score:* ${f['Lead Score'] ?? 'N/A'} (${f.Priority ?? 'unscored'})\n` +
    `*Territory:* ${territory}\n` +
    `*Reasoning:* ${f['AI Reasoning'] ?? 'n/a'}`;

  messages.push({ channel: CHANNELS.salesLeads, text: salesText });

  const score = Number(f['Lead Score']) || 0;
  if (score >= HIGH_PRIORITY_THRESHOLD) {
    messages.push({
      channel: CHANNELS.founders,
      text: `🔥 *High-priority lead*: ${f.Company} (score ${score}) just routed to ${repPool}.`,
    });
  }

  const attributableSource = ['website', 'typeform', 'tally'].includes(f.Source);
  if (attributableSource) {
    messages.push({
      channel: CHANNELS.marketing,
      text: `New ${f.Source} lead: ${f.Company} — attribution logged.`,
    });
  }

  return { messages };
};
